(window.webpackJsonp=window.webpackJsonp||[]).push([[977],{947:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">maxProfit</span><span class=\\"hljs-params\\">(self, k, prices)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type k: int\\n        :type prices: List[int]\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        n=len(prices)\\n        <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">maxProfit</span><span class=\\"hljs-params\\">(prices)</span>:</span>\\n          pSum=<span class=\\"hljs-number\\">0</span>\\n          <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,len(prices)):\\n            gap=prices[i]-prices[i<span class=\\"hljs-number\\">-1</span>]\\n            <span class=\\"hljs-keyword\\">if</span> gap&gt;<span class=\\"hljs-number\\">0</span>:\\n              pSum+=gap\\n          <span class=\\"hljs-keyword\\">return</span> pSum\\n        <span class=\\"hljs-keyword\\">if</span> k&gt;n/<span class=\\"hljs-number\\">2</span>:\\n          <span class=\\"hljs-keyword\\">return</span> maxProfit(prices)\\n        dp=[[<span class=\\"hljs-number\\">0</span>]*n <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(k+<span class=\\"hljs-number\\">1</span>)]\\n        \\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,k+<span class=\\"hljs-number\\">1</span>):\\n          curGap=float(<span class=\\"hljs-string\\">\'-inf\'</span>)\\n          <span class=\\"hljs-keyword\\">for</span> j <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,n):\\n            curGap=max(curGap,dp[i<span class=\\"hljs-number\\">-1</span>][j<span class=\\"hljs-number\\">-1</span>]-prices[j<span class=\\"hljs-number\\">-1</span>])\\n            <span class=\\"hljs-comment\\"># print i,j,dp</span>\\n            dp[i][j]=max(dp[i][j<span class=\\"hljs-number\\">-1</span>],prices[j]+curGap)\\n        <span class=\\"hljs-comment\\"># print dp</span>\\n        <span class=\\"hljs-keyword\\">return</span> dp[<span class=\\"hljs-number\\">-1</span>][<span class=\\"hljs-number\\">-1</span>]\\n</code></pre>\\n"],"titleSlug":"best-time-to-buy-and-sell-stock-iv","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u6574\u6570\u6570\u7ec4\xa0<code>prices</code> \uff0c\u5b83\u7684\u7b2c<em> </em><code>i</code> \u4e2a\u5143\u7d20\xa0<code>prices[i]</code> \u662f\u4e00\u652f\u7ed9\u5b9a\u7684\u80a1\u7968\u5728\u7b2c <code>i</code><em> </em>\u5929\u7684\u4ef7\u683c\u3002</p>\\n\\n<p>\u8bbe\u8ba1\u4e00\u4e2a\u7b97\u6cd5\u6765\u8ba1\u7b97\u4f60\u6240\u80fd\u83b7\u53d6\u7684\u6700\u5927\u5229\u6da6\u3002\u4f60\u6700\u591a\u53ef\u4ee5\u5b8c\u6210 <strong>k</strong> \u7b14\u4ea4\u6613\u3002</p>\\n\\n<p><strong>\u6ce8\u610f\uff1a</strong>\u4f60\u4e0d\u80fd\u540c\u65f6\u53c2\u4e0e\u591a\u7b14\u4ea4\u6613\uff08\u4f60\u5fc5\u987b\u5728\u518d\u6b21\u8d2d\u4e70\u524d\u51fa\u552e\u6389\u4e4b\u524d\u7684\u80a1\u7968\uff09\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>k = 2, prices = [2,4,1]\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u5728\u7b2c 1 \u5929 (\u80a1\u7968\u4ef7\u683c = 2) \u7684\u65f6\u5019\u4e70\u5165\uff0c\u5728\u7b2c 2 \u5929 (\u80a1\u7968\u4ef7\u683c = 4) \u7684\u65f6\u5019\u5356\u51fa\uff0c\u8fd9\u7b14\u4ea4\u6613\u6240\u80fd\u83b7\u5f97\u5229\u6da6 = 4-2 = 2 \u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>k = 2, prices = [3,2,6,5,0,3]\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n<strong>\u89e3\u91ca\uff1a</strong>\u5728\u7b2c 2 \u5929 (\u80a1\u7968\u4ef7\u683c = 2) \u7684\u65f6\u5019\u4e70\u5165\uff0c\u5728\u7b2c 3 \u5929 (\u80a1\u7968\u4ef7\u683c = 6) \u7684\u65f6\u5019\u5356\u51fa, \u8fd9\u7b14\u4ea4\u6613\u6240\u80fd\u83b7\u5f97\u5229\u6da6 = 6-2 = 4 \u3002\\n     \u968f\u540e\uff0c\u5728\u7b2c 5 \u5929 (\u80a1\u7968\u4ef7\u683c = 0) \u7684\u65f6\u5019\u4e70\u5165\uff0c\u5728\u7b2c 6 \u5929 (\u80a1\u7968\u4ef7\u683c = 3) \u7684\u65f6\u5019\u5356\u51fa, \u8fd9\u7b14\u4ea4\u6613\u6240\u80fd\u83b7\u5f97\u5229\u6da6 = 3-0 = 3 \u3002</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= k <= 100</code></li>\\n\\t<li><code>0 <= prices.length <= 1000</code></li>\\n\\t<li><code>0 <= prices[i] <= 1000</code></li>\\n</ul>\\n","title":"188. \u4e70\u5356\u80a1\u7968\u7684\u6700\u4f73\u65f6\u673a IV","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Hard","lang":["python"],"uniqueID":"188"}')}}]);